SELECT COUNT(*) AS total_records 
FROM resale_transactions 
WHERE town_id = 15 AND flat_type_id != 2;

SELECT *
FROM resale_transactions
WHERE resale_price >= (SELECT AVG(resale_price) FROM resale_transactions);

SELECT AVG(resale_price) AS average_resale_price
FROM resale_transactions rt
WHERE rt.flat_type_id = (SELECT flat_type_id FROM flat_types WHERE flat_type_name = '2 ROOM');

SELECT transaction_id, resale_price,
RANK() OVER(ORDER BY resale_price DESC) as price_rank
FROM resale_transactions;

SELECT AVG(t.median_income) AS average_median_income
FROM towns t
JOIN resale_transactions rt ON t.town_id = rt.town_id;
